package main

import (
	"container/heap"
	"math"
)

// Edge structure for graph representation
type Edge struct {
	to     int64
	weight int64
}

// Priority Queue item
type Item struct {
	node int64
	cost int64
}

// A PriorityQueue implements heap.Interface and holds Items.
type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// We want Pop to give us the minimum cost
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

// dijkstra calculates the shortest path distances from a start node to all other nodes
func dijkstra(n int64, graph [][]Edge, startNode int64) []int64 {
	distances := make([]int64, n)
	for i := range distances {
		distances[i] = math.MaxInt64
	}
	distances[startNode] = 0

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Item{node: startNode, cost: 0})

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Item)
		u := current.node
		d := current.cost

		if d > distances[u] {
			continue
		}

		for _, edge := range graph[u] {
			v := edge.to
			weight := edge.weight
			if distances[u] != math.MaxInt64 && distances[u]+weight < distances[v] {
				distances[v] = distances[u] + weight
				heap.Push(&pq, &Item{node: v, cost: distances[v]})
			}
		}
	}
	return distances
}

func solve(n int64, prices []int64, roads [][]int64) []int64 {
	// N is the number of shops
	N := n

	// 1. Build graphs
	graphEmpty := make([][]Edge, N)
	graphCarry := make([][]Edge, N)

	for _, road := range roads {
		u := road[0]
		v := road[1]
		cost := road[2]
		tax := road[3]

		// Empty travel (weight = cost)
		// Bidirectional
		graphEmpty[u] = append(graphEmpty[u], Edge{to: v, weight: cost})
		graphEmpty[v] = append(graphEmpty[v], Edge{to: u, weight: cost})

		// Carrying travel (weight = cost * tax)
		// Bidirectional
		carryWeight := cost * tax
		graphCarry[u] = append(graphCarry[u], Edge{to: v, weight: carryWeight})
		graphCarry[v] = append(graphCarry[v], Edge{to: u, weight: carryWeight})
	}

	// 2. Calculate All-Pairs Shortest Paths (APSP)
	// DistEmpty[i][j] = shortest path i -> j empty
	DistEmpty := make([][]int64, N)
	// DistCarry[i][j] = shortest path i -> j carrying
	DistCarry := make([][]int64, N)

	for i := int64(0); i < N; i++ {
		DistEmpty[i] = dijkstra(N, graphEmpty, i)
		DistCarry[i] = dijkstra(N, graphCarry, i)
	}

	// 3. Calculate the minimum cost for each shop i
	ans := make([]int64, N)

	for i := int64(0); i < N; i++ {
		// Option 1: Buy directly at shop i
		minCost := prices[i]

		// Option 2: Travel i -> j (empty), buy at j, travel j -> i (carrying)
		for j := int64(0); j < N; j++ {
			if i == j {
				// Handled by Option 1, or simply path cost is 0 + prices[i] + 0
				continue
			}

			// D_empty(i, j)
			costToJEmpty := DistEmpty[i][j]
			// D_carry(j, i)
			costBackToICarry := DistCarry[j][i]

			// Check for unreachable paths
			if costToJEmpty == math.MaxInt64 || costBackToICarry == math.MaxInt64 {
				continue
			}

			// Total cost = Travel i->j (empty) + Price[j] + Travel j->i (carrying)
			currentTotalCost := costToJEmpty + prices[j] + costBackToICarry

			if currentTotalCost < minCost {
				minCost = currentTotalCost
			}
		}
		ans[i] = minCost
	}

	return ans
}
