const INF = Number.MAX_SAFE_INTEGER;

/**
 * Basic MinPriorityQueue implementation for Dijkstra's algorithm.
 * Stores [distance, node].
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    getParentIndex(i) { return Math.floor((i - 1) / 2); }
    getLeftChildIndex(i) { return 2 * i + 1; }
    getRightChildIndex(i) { return 2 * i + 2; }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    // Comparison function: compares based on distance (the first element of the pair)
    compare(a, b) {
        return a[0] < b[0];
    }

    insert(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    bubbleUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = this.getParentIndex(currentIndex);
            if (this.compare(this.heap[currentIndex], this.heap[parentIndex])) {
                this.swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    extractMin() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.sinkDown(0);
        return min;
    }

    sinkDown(index) {
        let currentIndex = index;
        const length = this.heap.length;

        while (true) {
            let left = this.getLeftChildIndex(currentIndex);
            let right = this.getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            // Check left child
            if (left < length && this.compare(this.heap[left], this.heap[smallest])) {
                smallest = left;
            }

            // Check right child
            if (right < length && this.compare(this.heap[right], this.heap[smallest])) {
                smallest = right;
            }

            if (smallest !== currentIndex) {
                this.swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
}


/**
 * Runs Dijkstra's algorithm from a starting node on a weighted graph.
 * @param {number} startNode - The starting node index.
 * @param {number} N - Total number of nodes.
 * @param {Array<Array<{to: number, weight: number}>>} adj - Adjacency list representation of the graph.
 * @returns {Array<number>} Array where result[i] is the shortest distance from startNode to i.
 */
function dijkstra(startNode, N, adj) {
    const distances = new Array(N).fill(INF);
    distances[startNode] = 0;

    const pq = new MinPriorityQueue();
    // Store [distance, node]
    pq.insert([0, startNode]);

    while (!pq.isEmpty()) {
        const [d, u] = pq.extractMin();

        if (d > distances[u]) {
            continue;
        }

        for (const edge of adj[u]) {
            const v = edge.to;
            const weight = edge.weight;

            const newDist = d + weight;

            if (newDist < distances[v]) {
                distances[v] = newDist;
                pq.insert([newDist, v]);
            }
        }
    }
    return distances;
}


function solve(n, prices, roads) {
    // 1. Build two graphs: G_empty and G_apple

    // Adjacency list: adj[u] = [{to: v, weight: w}, ...]
    const adjEmpty = Array.from({ length: n }, () => []);
    const adjApple = Array.from({ length: n }, () => []);

    for (const [u, v, cost, tax] of roads) {
        // Empty travel (cost)
        adjEmpty[u].push({ to: v, weight: cost });
        adjEmpty[v].push({ to: u, weight: cost });

        // Apple travel (cost * tax)
        const appleCost = cost * tax;
        adjApple[u].push({ to: v, weight: appleCost });
        adjApple[v].push({ to: u, weight: appleCost });
    }

    // 2. Run N Dijkstra instances for both graphs

    // D_E[i][j] = Min cost i -> j while empty
    const D_E = Array.from({ length: n }, () => new Array(n).fill(INF));
    // D_A[j][i] = Min cost j -> i while carrying apple
    const D_A = Array.from({ length: n }, () => new Array(n).fill(INF));

    // Calculate D_E (Empty travel costs)
    for (let i = 0; i < n; i++) {
        const distances = dijkstra(i, n, adjEmpty);
        for (let j = 0; j < n; j++) {
            D_E[i][j] = distances[j];
        }
    }

    // Calculate D_A (Apple travel costs)
    // We run Dijkstra from j and store the result in D_A[j]
    for (let j = 0; j < n; j++) {
        const distances = dijkstra(j, n, adjApple);
        for (let i = 0; i < n; i++) {
            // D_A[j][i] stores the shortest path from j (start) to i (end)
            D_A[j][i] = distances[i];
        }
    }

    // 3. Calculate the final minimum cost for each store i
    const ans = new Array(n);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly
        let minCost = prices[i];

        // Option 2: Go to store j, buy, and return to i
        for (let j = 0; j < n; j++) {
            // Cost(i -> j, empty) + prices[j] + Cost(j -> i, apple)

            // Check if paths exist before calculation to avoid INF + finite number issues 
            // that might wrap around or lead to incorrect results if INF isn't handled perfectly.
            if (D_E[i][j] !== INF && D_A[j][i] !== INF) {
                // Use BigInt temporarily for addition safety if intermediate sums approach 2^53, 
                // although 10^14 fits in standard JS number type. We stick to standard numbers 
                // since 10^14 < 9e15.
                const indirectCost = D_E[i][j] + prices[j] + D_A[j][i];
                if (indirectCost < minCost) {
                    minCost = indirectCost;
                }
            }
        }
        ans[i] = minCost;
    }

    return ans;
}
