package main

import (
	"container/heap"
	"math"
)

// Edge represents a connection in the graph
type Edge struct {
	to     int
	weight int64
}

// PriorityQueue item
type Item struct {
	node     int
	distance int64
}

// PriorityQueue implements heap.Interface and holds Items.
type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// We want a min-heap, so we compare distances
	return pq[i].distance < pq[j].distance
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

// dijkstra computes the shortest path distances from a source node 'startNode'
// using the provided adjacency list 'adj'.
func dijkstra(n int, adj [][]Edge, startNode int) []int64 {
	distances := make([]int64, n)
	infinity := int64(math.MaxInt64)
	for i := range distances {
		distances[i] = infinity
	}
	distances[startNode] = 0

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Item{node: startNode, distance: 0})

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Item)
		u := current.node
		d := current.distance

		if d > distances[u] {
			continue
		}

		for _, edge := range adj[u] {
			v := edge.to
			weight := edge.weight
			newDist := distances[u] + weight

			if newDist < distances[v] {
				distances[v] = newDist
				heap.Push(&pq, &Item{node: v, distance: newDist})
			}
		}
	}
	return distances
}

func solve(n int64, prices []int64, roads [][]int64) []int64 {
	N := int(n)

	// 1. Build Adjacency Lists
	adjEmpty := make([][]Edge, N)
	adjCarry := make([][]Edge, N)

	for _, road := range roads {
		u, v, cost, tax := int(road[0]), int(road[1]), road[2], road[3]

		// Empty Graph (G_empty): weight = cost
		// Bidirectional
		adjEmpty[u] = append(adjEmpty[u], Edge{to: v, weight: cost})
		adjEmpty[v] = append(adjEmpty[v], Edge{to: u, weight: cost})

		// Carry Graph (G_carry): weight = cost * tax
		// Bidirectional
		carryWeight := cost * tax
		adjCarry[u] = append(adjCarry[u], Edge{to: v, weight: carryWeight})
		adjCarry[v] = append(adjCarry[v], Edge{to: u, weight: carryWeight})
	}

	// 2. All-Pairs Shortest Path (Run Dijkstra N times for each graph)

	// DistE[i][j] = D_empty(i, j)
	distEmpty := make([][]int64, N)
	for i := range distEmpty {
		distEmpty[i] = dijkstra(N, adjEmpty, i)
	}

	// DistC[i][j] = D_carry(i, j)
	distCarry := make([][]int64, N)
	for i := range distCarry {
		distCarry[i] = dijkstra(N, adjCarry, i)
	}

	// 3. Calculate Final Answer
	ans := make([]int64, N)
	infinity := int64(math.MaxInt64)

