package main

import (
	"container/heap"
	"math"
)

// Item structure for Priority Queue in Dijkstra's algorithm
type Item struct {
	node     int
	distance int64
}

// PriorityQueue implementation
type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// We want the minimum distance, so we use <
	return pq[i].distance < pq[j].distance
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

// Dijkstra computes the shortest path distances from a starting node to all other nodes
func dijkstra(n int, adj [][]Edge, startNode int) []int64 {
	distances := make([]int64, n)
	for i := range distances {
		distances[i] = math.MaxInt64
	}
	distances[startNode] = 0

	pq := make(PriorityQueue, 1)
	pq[0] = &Item{node: startNode, distance: 0}
	heap.Init(&pq)

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Item)
		u := current.node
		d := current.distance

		if d > distances[u] {
			continue
		}

		for _, edge := range adj[u] {
			v := edge.to
			weight := edge.weight

			newDist := distances[u] + weight
			if newDist < distances[v] {
				distances[v] = newDist
				heap.Push(&pq, &Item{node: v, distance: newDist})
			}
		}
	}
	return distances
}

// Edge structure for adjacency list
type Edge struct {
	to     int
	weight int64
}

func solve(n int64, prices []int64, roads [][]int64) []int64 {
	N := int(n)

	// Graph E: Empty-handed travel costs (cost)
	adjE := make([][]Edge, N)
	// Graph C: Carrying apple costs (cost * tax)
	adjC := make([][]Edge, N)

	for _, road := range roads {
		u := int(road[0])
		v := int(road[1])
		cost := road[2]
		tax := road[3]

		// Graph E setup (Symmetric)
		adjE[u] = append(adjE[u], Edge{to: v, weight: cost})
		adjE[v] = append(adjE[v], Edge{to: u, weight: cost})

		// Graph C setup (Symmetric)
		carryCost := cost * tax
		adjC[u] = append(adjC[u], Edge{to: v, weight: carryCost})
		adjC[v] = append(adjC[v], Edge{to: u, weight: carryCost})
	}

	ans := make([]int64, N)

	// We need to calculate ans[i] = min_{j=0}^{N-1} { D_E(i, j) + D_C(i, j) + prices[j] }
	// D_E(i, j) is shortest path i->j empty.
	// D_C(i, j) is shortest path i->j carry. Since carry path j->i is required, and costs are symmetric, D_C(j, i) = D_C(i, j).

	for i := 0; i < N; i++ {
		// 1. Calculate shortest paths from i in Empty Graph
		distEmpty := dijkstra(N, adjE, i)

		// 2. Calculate shortest paths from i in Carry Graph
		distCarry := dijkstra(N, adjC, i)

		minCost := prices[i] // Initial cost is buying directly at i (j=i)

		// 3. Check all potential buying locations j
		for j := 0; j < N; j++ {
			if i == j {
				continue // Already covered by initial minCost = prices[i]
			}

			// Check if paths exist
			if distEmpty[j] == math.MaxInt64 || distCarry[j] == math.MaxInt64 {
				continue // Cannot reach j or return from j
			}

			// Total Cost = Path(i->j, empty) + prices[j] + Path(j->i, carry)
			// Since paths are symmetric w.r.t start/end for both graphs:
			// Total Cost = distEmpty[j] + prices[j] + distCarry[j]

			currentCost := distEmpty[j] + distCarry[j] + prices[j]

			if currentCost < minCost {
				minCost = currentCost
			}
		}
		ans[i] = minCost
	}

	return ans
}
