import (
	"container/heap"
	"math"
)

// Edge represents a connection in the graph
type Edge struct {
	to     int
	weight int64
}

// PriorityQueueItem stores distance and node for Dijkstra's algorithm
type PriorityQueueItem struct {
	node     int
	distance int64
}

// PriorityQueue implements heap.Interface for Dijkstra's algorithm
type PriorityQueue []*PriorityQueueItem

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// We want a min-heap based on distance
	return pq[i].distance < pq[j].distance
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*PriorityQueueItem)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

// dijkstra computes single-source shortest paths from startNode using the given graph
func dijkstra(n int, graph [][]Edge, startNode int) []int64 {
	distances := make([]int64, n)
	infinity := int64(math.MaxInt64)
	for i := range distances {
		distances[i] = infinity
	}

	distances[startNode] = 0

	pq := make(PriorityQueue, 1)
	pq[0] = &PriorityQueueItem{node: startNode, distance: 0}
	heap.Init(&pq)

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*PriorityQueueItem)
		u := item.node
		d := item.distance

		if d > distances[u] {
			continue
		}

		for _, edge := range graph[u] {
			v := edge.to
			weight := edge.weight
			newDist := distances[u] + weight

			if newDist < distances[v] {
				distances[v] = newDist
				heap.Push(&pq, &PriorityQueueItem{node: v, distance: newDist})
			}
		}
	}
	return distances
}

func solve(n int64, prices []int64, roads [][]int64) []int64 {
	N := int(n)

	// --- 1. Build Graph Structures ---

	// Graph for empty travel (Cost = cost_i)
	adjE := make([][]Edge, N)
	// Graph for carrying travel (Cost = cost_i * tax_i)
	adjC := make([][]Edge, N)

	for _, road := range roads {
		u := int(road[0])
		v := int(road[1])
		cost := road[2]
		tax := road[3]

		// Empty Travel (bidirectional)
		adjE[u] = append(adjE[u], Edge{to: v, weight: cost})
		adjE[v] = append(adjE[v], Edge{to: u, weight: cost})

		// Carrying Travel (bidirectional)
		carryCost := cost * tax
		adjC[u] = append(adjC[u], Edge{to: v, weight: carryCost})
		adjC[v] = append(adjC[v], Edge{to: u, weight: carryCost})
	}

	// --- 2. Calculate All-Pairs Shortest Paths ---

	// DistE[i][j]: Minimum cost to travel from i to j empty-handed
	DistE := make([][]int64, N)
	// DistC[i][j]: Minimum cost to travel from i to j carrying apples
	DistC := make([][]int64, N)
	infinity := int64(math.MaxInt64)

	for i := 0; i < N; i++ {
		DistE[i] = make([]int64, N)
		DistC[i] = make([]int64, N)

		// Run Dijkstra for Empty travel starting at i
		distsE := dijkstra(N, adjE, i)
		copy(DistE[i], distsE)

		// Run Dijkstra for Carrying travel starting at i
		distsC := dijkstra(N, adjC, i)
		copy(DistC[i], distsC)
	}

	// --- 3. Calculate Final Minimum Cost for each store i ---

	ans := make([]int64, N)

	for i := 0; i < N; i++ {
		// Option 1: Buy directly at i
		minCost := prices[i]

		// Option 2: Travel i -> j (empty) -> Buy j -> j -> i (carrying)
		for j := 0; j < N; j++ {
			// Cost(i -> j empty) + prices[j] + Cost(j -> i carrying)

			travelToJ := DistE[i][j]
			travelFromJ := DistC[j][i] // This is the cost from J back to I carrying apples

			// Check for unreachable paths
			if travelToJ == infinity || travelFromJ == infinity {
				continue
			}

			totalCost := travelToJ + prices[j] + travelFromJ

			if totalCost < minCost {
				minCost = totalCost
			}
		}
		ans[i] = minCost
	}

	return ans
}

